type TradingLimit = {
    /**
     * the minimum allowed size of order
     */
    minSize: number;
    /**
     * the maximum allowed size of order
     */
    maxSize: number;
    /**
     * all the size value should be a multiple of stepSize
     */
    stepSize: number;
    /**
     * the minimum allowed price
     */
    minPrice: number;
    /**
     * the maximum allowed price
     */
    maxPrice: number;
    /**
     * all the price value should be a multiple of stepPrice
     */
    stepPrice: number;
    /**
     * the minimum allowed notional
     *
     * minNotional = minPrice * minSize
     */
    minNotional: number;
    /**
     * the maximum allowed notional
     *
     * maxNotional = maxPrice * maxSize
     */
    maxNotional: number;
    /**
     * the minimum allowed market size
     */
    marketMinSize: number;
    /**
     * the maximum allowed market size
     */
    marketMaxSize: number;
    /**
     * the step amount for the market
     */
    marketStepSize: number;
};
declare const defaultTradingLimit: TradingLimit;

