declare enum MarketTimeInForce {
    /**
     * FOK - Fill or kill
     * The order must be filled entirely or not at all.
     */
    FOK = "FOK",
    /**
     * FAK - Fill and kill
     * The order can be partially filled, and any unfilled portion is canceled.
     */
    FAK = "FAK"
}
declare enum LimitTimeInForce {
    /**
     * GTC - Good till cancelled
     */
    GTC = "GTC",
    /**
     * GTD - Good till date
     */
    GTD = "GTD",
    /**
     * IOC - Immediate or cancel
     */
    IOC = "IOC"
}
type TimeInForce = MarketTimeInForce | LimitTimeInForce;
type Order<TType extends 'market' | 'limit' | undefined = 'market' | 'limit'> = {
    chainId?: number;
    /**
     * Signer of the order
     */
    signer?: Address;
    /**
     * Token ID of the Conditional token asset being traded
     */
    tokenId: string;
    /**
     * usd price order to be executed at
     *
     */
    price: number;
    /**
     * Order size, denominated in ConditionalToken units
     */
    size?: number;
    /**
     * Order value, denominated in CollateralToken units
     */
    value?: number;
    /**
     * Side of the order
     */
    side: OrderStructSide;
    /**
     * Nonce used for onchain cancellations
     */
    nonce?: number;
    /**
     * Type of the order
     * market or limit
     */
    type: TType;
    /**
     * Time in force for the order
     */
    timeInForce?: TimeInForce;
    /**
     * Expiration time for the order
     *
     * only for limit orders, unix timestamp in seconds
     */
    expiration?: TType extends 'market' ? never : number;
    signatureType?: OrderStructSignatureType;
    /**
     * Price slippage tolerance for the order
     *
     * only for market orders
     * if sell order, the price slippage tolerance is the maximum price order will be executed at
     * if buy order, the price slippage tolerance is the minimum price order will be executed at
     */
    priceLimit?: number;
};
type MarketOrder = Prettify<Omit<Order<'market' | undefined>, 'price' | 'expiration'> & {
    timeInForce?: MarketTimeInForce;
    price?: number;
    priceLimit?: number;
}>;
type LimitOrder = Prettify<Order<'limit' | undefined> & {
    timeInForce: LimitTimeInForce;
}>;
type UnsignedOrderStruct = Prettify<Omit<OrderStruct, 'signature'>>;
type UnsignedOrder = Prettify<Omit<OrderStruct, 'signature'> & {
    timeInForce: TimeInForce;
}>;
type MarketUnsignedOrder = Prettify<Omit<OrderStruct, 'signature'> & {
    timeInForce: MarketTimeInForce;
}>;
type LimitUnsignedOrder = Prettify<Omit<OrderStruct, 'signature'> & {
    timeInForce: LimitTimeInForce;
}>;
type SignedOrder = Prettify<OrderStruct & {
    timeInForce: TimeInForce;
}>;

